describe("performance.timeOrigin",()=>{it("should have a positive value",()=>{expect(Number(performance.timeOrigin)).toBeGreaterThanOrEqual(0)})});describe("performance.now()",()=>{it("should have a positive value",()=>{expect(Number(performance.now())).toBeGreaterThanOrEqual(0)}),it("should be a monotonic clock",()=>{let e=performance.now(),r=performance.now();expect(Number(r)).toBeGreaterThanOrEqual(Number(e))}),describe("performance.toJSON()",()=>{it("performance.toJSON().timeOrigin should have a positive value",()=>{expect(Number(performance.toJSON().timeOrigin)).toBeGreaterThanOrEqual(0)}),it("performance.toJSON().timeOrigin should match performance.timeOrigin",()=>{expect(performance.toJSON().timeOrigin).toEqual(performance.timeOrigin)})})});
